   129→    pub fn jjrf_parse(input: &str) -> Result<Self, String> {
   130→        let stripped = input.strip_prefix(JJRF_CORONET_PREFIX).unwrap_or(input);
   131→        if stripped.len() != 5 {
   132→            return Err(format!(
   133→                "Coronet must be 5 base64 characters (with or without {} prefix), got '{}'",
   134→                JJRF_CORONET_PREFIX, input
   135→            ));
   136→        }
   137→        // Validate all characters are in charset
   138→        for c in stripped.chars() {
   139→            zjjrf_char_to_value(c)?;
   140→        }
   141→        Ok(jjrf_Coronet(stripped.to_string()))
   142→    }
